import React, { useEffect, useRef, useState } from 'react';
import io from 'socket.io-client';
import Peer from 'simple-peer';

const VideoCall = ({ roomId, userId, onLeave, serverUrl }) => {
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [remoteStreams, setRemoteStreams] = useState(new Map());
  const [isAudioEnabled, setIsAudioEnabled] = useState(true);
  const [isVideoEnabled, setIsVideoEnabled] = useState(true);
  const [connectionStatus, setConnectionStatus] = useState('connecting');
  const [socketId, setSocketId] = useState('');
  const [hasJoinedRoom, setHasJoinedRoom] = useState(false);
  
  const socketRef = useRef();
  const peersRef = useRef([]);
  const localVideoRef = useRef();
  const localStreamRef = useRef(null);
  const remoteVideosRef = useRef(new Map());
  const pendingOffersRef = useRef([]);
  const pendingParticipantsRef = useRef([]);
  const pendingUsersRef = useRef([]); // Add this for users who connect while stream isn't ready

  useEffect(() => {
    console.log('Initializing VideoCall with roomId:', roomId, 'userId:', userId);
    
    socketRef.current = io(serverUrl, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 5,
      reconnectionDelay: 1000,
      timeout: 20000,
      forceNew: true
    });

    socketRef.current.on('connect', () => {
      console.log('✅ Socket connected with ID:', socketRef.current.id);
      setSocketId(socketRef.current.id);
      setConnectionStatus('connected');
      
      console.log('📷 STEP 1: Requesting camera access...');
      const constraints = {
        video: {
          width: { ideal: 640 },
          height: { ideal: 480 },
          frameRate: { ideal: 30 },
          facingMode: "user"
        },
        audio: {
          echoCancellation: true,
          noiseSuppression: true
        }
      };

      navigator.mediaDevices.getUserMedia(constraints)
        .then(stream => {
          console.log('✅ STEP 2: Got local stream successfully');
          setLocalStream(stream);
          localStreamRef.current = stream;
          if (localVideoRef.current) {
            localVideoRef.current.srcObject = stream;
          }

          // Connect to any users who joined while we were busy
          if (pendingUsersRef.current.length > 0) {
            console.log('👥 Connecting to pending users:', pendingUsersRef.current);
            pendingUsersRef.current.forEach(socketId => {
              if (socketId !== socketRef.current.id) {
                createPeer(socketId, false);
              }
            });
            pendingUsersRef.current = [];
          }

          console.log('✅ STEP 3: Camera ready, joining room now...');
          socketRef.current.emit('join-room', { roomId, userId });
          setHasJoinedRoom(true);
          
          console.log('📋 STEP 4: Checking pending offers:', pendingOffersRef.current.length);
          pendingOffersRef.current.forEach(({ offer, from }) => {
            console.log('Creating peer for queued offer from:', from);
            createPeer(from, false, offer);
          });
          pendingOffersRef.current = [];

          console.log('👥 STEP 5: Checking pending participants:', pendingParticipantsRef.current.length);
          pendingParticipantsRef.current.forEach(participant => {
            if (participant.socketId !== socketRef.current.id) {
              console.log('Creating peer for pending participant:', participant);
              createPeer(participant.socketId, true);
            }
          });
          pendingParticipantsRef.current = [];
        })
        .catch(error => {
          console.error('❌ Error accessing media devices:', error);
          setConnectionStatus('error');
          
          if (error.name === 'NotAllowedError') {
            alert('Please allow camera and microphone access');
          } else if (error.name === 'NotFoundError') {
            alert('No camera or microphone found');
          } else {
            alert(`Could not access camera: ${error.message}`);
          }
        });
    });

    socketRef.current.on('connect_error', (error) => {
      console.error('❌ Socket connection error:', error);
      setConnectionStatus('error');
    });

    socketRef.current.on('disconnect', (reason) => {
      console.log('Socket disconnected:', reason);
      setConnectionStatus('connecting');
    });

    socketRef.current.on('reconnect', (attemptNumber) => {
      console.log('Socket reconnected after', attemptNumber, 'attempts');
      setConnectionStatus('connected');
    });

    socketRef.current.on('room-joined', ({ participants, isHost }) => {
      console.log('🏠 Room joined! Participants:', participants);
      
      if (!localStreamRef.current) {
        console.log('⏳ No stream yet, saving participants for later');
        pendingParticipantsRef.current = participants;
        return;
      }

      participants.forEach(participant => {
        if (participant.socketId !== socketRef.current.id) {
          console.log('Creating peer for participant:', participant);
          createPeer(participant.socketId, true);
        }
      });
    });

    socketRef.current.on('user-connected', ({ userId, socketId }) => {
      console.log('👤 User connected:', userId, socketId);
      
      if (!localStreamRef.current) {
        console.log('⏳ No stream yet, saving user for later:', userId);
        pendingUsersRef.current.push(socketId);
        return;
      }
      
      if (socketId !== socketRef.current.id) {
        createPeer(socketId, false);
      }
    });

    socketRef.current.on('user-disconnected', ({ socketId, userId }) => {
      console.log('👤 User disconnected:', userId);
      
      const peerIndex = peersRef.current.findIndex(p => p.peerID === socketId);
      if (peerIndex !== -1) {
        peersRef.current[peerIndex].peer.destroy();
        peersRef.current.splice(peerIndex, 1);
      }
      
      setRemoteStreams(prev => {
        const newMap = new Map(prev);
        newMap.delete(socketId);
        return newMap;
      });
      
      remoteVideosRef.current.delete(socketId);

      setPeers(peersRef.current.map(p => p.peerID));
    });

    socketRef.current.on('offer', ({ offer, from }) => {
      console.log('📞 Received offer from:', from);
      
      if (!localStreamRef.current) {
        console.log('⏳ No stream yet, queueing offer');
        pendingOffersRef.current.push({ offer, from });
        return;
      }
      
      const peerExists = peersRef.current.find(p => p.peerID === from);
      if (!peerExists) {
        createPeer(from, false, offer);
      }
    });

    socketRef.current.on('answer', ({ answer, from }) => {
      console.log('📞 Received answer from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer) {
        peer.peer.signal(answer);
      }
    });

    socketRef.current.on('ice-candidate', ({ candidate, from }) => {
      console.log('📞 Received ICE candidate from:', from);
      const peer = peersRef.current.find(p => p.peerID === from);
      if (peer && candidate) {
        peer.peer.signal(candidate);
      }
    });

    socketRef.current.on('error', ({ message }) => {
      console.error('Room error:', message);
      
      if (message === 'Room not found') {
        alert('This room no longer exists. Please create a new room.');
        setTimeout(() => onLeave(), 2000);
      } else if (message === 'Room is full') {
        alert('This room is full. Please try another room or create a new one.');
        setTimeout(() => onLeave(), 2000);
      }
    });

    return () => {
      console.log('Cleaning up...');
      peersRef.current.forEach(peer => peer.peer.destroy());
      if (localStream) {
        localStream.getTracks().forEach(track => track.stop());
      }
      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, [roomId, userId, serverUrl]);

  const createPeer = (targetSocketId, initiator, offer = null) => {
    if (!localStreamRef.current) {
      console.log('Cannot create peer - no local stream');
      return;
    }

    console.log('Creating peer for:', targetSocketId, 'initiator:', initiator);

    const peer = new Peer({
      initiator: initiator,
      stream: localStreamRef.current,
      trickle: true,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' }
        ]
      }
    });

    peersRef.current.push({
      peerID: targetSocketId,
      peer: peer
    });

    setPeers(peersRef.current.map(p => p.peerID));

    peer.on('signal', signal => {
      console.log('📡 Signal from peer:', targetSocketId, signal.type, initiator ? '(initiator)' : '(receiver)');
      
      if (signal.type === 'offer') {
        socketRef.current.emit('offer', {
          offer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (signal.type === 'answer') {
        socketRef.current.emit('answer', {
          answer: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      } else if (signal.type === 'candidate') {
        socketRef.current.emit('ice-candidate', {
          candidate: signal,
          to: targetSocketId,
          from: socketRef.current.id
        });
      }
    });

    peer.on('stream', stream => {
      console.log('🎥 Received stream from peer:', targetSocketId);
      console.log('🎥 Stream tracks:', stream.getTracks().length);
      
      // Store stream in state directly
      setRemoteStreams(prev => {
        const newMap = new Map(prev);
        newMap.set(targetSocketId, stream);
        return newMap;
      });
      
      // Also store in ref for cleanup
      remoteVideosRef.current.set(targetSocketId, stream);
    });

    peer.on('connect', () => {
      console.log('✅ Peer connected with:', targetSocketId);
    });

    peer.on('error', err => {
      console.error('❌ Peer error:', err);
    });

    if (offer) {
      console.log('Signaling offer to peer');
      peer.signal(offer);
    }
  };

  const toggleAudio = () => {
    if (localStream) {
      localStream.getAudioTracks().forEach(track => {
        track.enabled = !isAudioEnabled;
      });
      setIsAudioEnabled(!isAudioEnabled);
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      localStream.getVideoTracks().forEach(track => {
        track.enabled = !isVideoEnabled;
      });
      setIsVideoEnabled(!isVideoEnabled);
    }
  };

  const getConnectionStatusColor = () => {
    switch(connectionStatus) {
      case 'connected': return 'bg-green-500';
      case 'connecting': return 'bg-yellow-500';
      case 'error': return 'bg-red-500';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div className="space-y-4">
      {/* Connection Status Bar */}
      <div className="bg-white rounded-lg shadow-md p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <div className={`h-3 w-3 rounded-full ${getConnectionStatusColor()}`}></div>
            <span className="text-sm font-medium text-gray-700">
              {connectionStatus === 'connected' ? 'Connected' : 
               connectionStatus === 'connecting' ? 'Connecting...' : 'Error'}
            </span>
            <span className="text-sm text-gray-600">
              Room: <span className="font-mono font-bold">{roomId}</span>
            </span>
            <span className="text-sm text-gray-600">
              Users: <span className="font-bold">{peers.length + 1}</span>
            </span>
          </div>
          <button
            onClick={onLeave}
            className="bg-red-500 text-white px-4 py-2 rounded hover:bg-red-600 transition text-sm"
          >
            Leave Call
          </button>
        </div>
      </div>

      {/* Video Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Local Video */}
        <div className="bg-black rounded-lg overflow-hidden relative aspect-video">
          <video
            ref={localVideoRef}
            autoPlay
            playsInline
            muted
            className="w-full h-full object-cover"
          />
          <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
            You {!isVideoEnabled && '(Video Off)'} {!isAudioEnabled && '(Muted)'}
          </div>
        </div>

        {/* Remote Videos - FIXED VERSION */}
        {Array.from(remoteStreams.entries()).map(([socketId, stream]) => (
          <div key={socketId} className="bg-black rounded-lg overflow-hidden relative aspect-video">
            <video
              ref={el => {
                if (el && !el.srcObject) {
                  console.log('🎥 Setting remote video for:', socketId);
                  el.srcObject = stream;
                  // Force play to handle autoplay restrictions
                  el.play().catch(e => console.log('Autoplay prevented:', e));
                }
              }}
              autoPlay
              playsInline
              muted={false}
              className="w-full h-full object-cover"
            />
            <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
              Peer {socketId.substring(0, 8)}
            </div>
          </div>
        ))}

        {/* Placeholder when no remote videos */}
        {remoteStreams.size === 0 && (
          <div className="bg-gray-800 rounded-lg p-8 text-center text-gray-400 flex items-center justify-center min-h-[200px] aspect-video">
            <div>
              <p>Waiting for others to join...</p>
              <p className="text-sm text-gray-500 mt-2">Share this room ID: {roomId}</p>
              {peers.length > 0 && (
                <p className="text-sm text-green-400 mt-2">✓ Peer connected, waiting for video...</p>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="bg-white rounded-lg shadow-md p-4">
        <div className="flex justify-center space-x-4">
          <button
            onClick={toggleAudio}
            className={`p-3 rounded-full ${
              isAudioEnabled ? 'bg-blue-500 hover:bg-blue-600' : 'bg-red-500 hover:bg-red-600'
            } text-white transition`}
            title={isAudioEnabled ? 'Mute' : 'Unmute'}
          >
            {isAudioEnabled ? '🔊' : '🔇'}
          </button>

          <button
            onClick={toggleVideo}
            className={`p-3 rounded-full ${
              isVideoEnabled ? 'bg-blue-500 hover:bg-blue-600' : 'bg-red-500 hover:bg-red-600'
            } text-white transition`}
            title={isVideoEnabled ? 'Turn off camera' : 'Turn on camera'}
          >
            {isVideoEnabled ? '📹' : '🚫'}
          </button>
        </div>
      </div>

      {/* Debug Info */}
      {process.env.NODE_ENV === 'development' && (
        <div className="bg-gray-800 text-green-400 p-4 rounded-lg font-mono text-xs">
          <div>Socket: {socketId || 'Not connected'}</div>
          <div>Status: {connectionStatus}</div>
          <div>Peers: {peers.length}</div>
          <div>Remote Streams: {remoteStreams.size}</div>
          <div>Pending Offers: {pendingOffersRef.current.length}</div>
          <div>Pending Users: {pendingUsersRef.current.length}</div>
          <div>Has Joined Room: {hasJoinedRoom ? 'Yes' : 'No'}</div>
        </div>
      )}
    </div>
  );
};

export default VideoCall;
